// State variables
let currentWeek = "";
let compareWeek = "";
let currentTab = "scurve-tab";
let chartInstances = {};

// Time resolution and slicer window state
let timeScale = "weekly"; // "weekly" or "monthly"
let slicerStart = "";
let slicerEnd = "";
let projectMinDate = "";
let projectMaxDate = "";

// Pagination state for list
let filteredDeliverables = [];
let currentPage = 1;
const itemsPerPage = 20;

// Initialize application
window.addEventListener('DOMContentLoaded', () => {
    if (!PROJECT_DATA || !PROJECT_DATA.control_weeks || PROJECT_DATA.control_weeks.length === 0) {
        console.error("No project data available.");
        return;
    }

    currentWeek = PROJECT_DATA.latest_week;

    // Populate control week dropdown
    const weekSelect = document.getElementById("controlWeekSelect");
    PROJECT_DATA.control_weeks.forEach(w => {
        const opt = document.createElement("option");
        opt.value = w;
        opt.textContent = formatDropdownLabel(w);
        if (w === currentWeek) opt.selected = true;
        weekSelect.appendChild(opt);
    });

    // Handle main week selection change
    weekSelect.addEventListener('change', (e) => {
        currentWeek = e.target.value;
        updateCompareDropdown();
        updateDashboard();
    });

    updateCompareDropdown();
    updateDashboard();
    switchTab('scurve-tab'); // Show S-curve initially
});

function formatDropdownLabel(dateStr) {
    const date = new Date(dateStr + "T00:00:00");
    const months = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
    return `W-${date.getDate()} ${months[date.getMonth()]} ${date.getFullYear().toString().substr(-2)}`;
}

