// Dynamic S-Curve Generation Engine
function calculateSCurveTimeline(deliverables, controlDateStr, scaleType, startDateStr, endDateStr) {
    const controlDate = new Date(controlDateStr + "T00:00:00");
    const startLimit = new Date(startDateStr + "T00:00:00");
    const endLimit = new Date(endDateStr + "T00:00:00");

    let timeline = [];
    let labels = [];

    if (scaleType === "weekly") {
        // Use master weeks from latest dataset
        const masterWeeks = PROJECT_DATA.weekly_data[PROJECT_DATA.latest_week].s_curves.weeks;
        masterWeeks.forEach(wStr => {
            const wDate = new Date(wStr + "T00:00:00");
            if (wDate >= startLimit && wDate <= endLimit) {
                timeline.push(wStr);
                labels.push(formatWeekLabel(wStr));
            }
        });
    } else {
        // Generate monthly end dates
        let curr = new Date(startLimit.getFullYear(), startLimit.getMonth(), 1);
        while (curr <= endLimit) {
            const lastDay = new Date(curr.getFullYear(), curr.getMonth() + 1, 0);
            const wStr = lastDay.toISOString().split('T')[0];
            timeline.push(wStr);

            const months = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
            labels.push(`${months[curr.getMonth()]}-${curr.getFullYear().toString().substr(-2)}`);

            curr.setMonth(curr.getMonth() + 1);
        }
    }

    if (timeline.length === 0) {
        return {
            weeks: [], labels: [],
            revb: { plan_periodic: [], plan_cum: [], fcst_periodic: [], fcst_cum: [], actual_periodic: [], actual_cum: [] },
            rev0: { plan_periodic: [], plan_cum: [], fcst_periodic: [], fcst_cum: [], actual_periodic: [], actual_cum: [] }
        };
    }

    function getBinDate(dateStr) {
        if (!dateStr) return null;
        const d = new Date(dateStr + "T00:00:00");
        for (let i = 0; i < timeline.length; i++) {
            const tDate = new Date(timeline[i] + "T00:00:00");
            if (d <= tDate) return timeline[i];
        }
        return timeline[timeline.length - 1];
    }

    const counts = {
        revb: { plan: {}, fcst: {}, real: {} },
        rev0: { plan: {}, fcst: {}, real: {} }
    };

    timeline.forEach(t => {
        counts.revb.plan[t] = 0; counts.revb.fcst[t] = 0; counts.revb.real[t] = 0;
        counts.rev0.plan[t] = 0; counts.rev0.fcst[t] = 0; counts.rev0.real[t] = 0;
    });

    deliverables.forEach(d => {
        const pB_bin = getBinDate(d.plan_date_b);
        const fB_bin = getBinDate(d.fcst_date_b);
        const rB_bin = getBinDate(d.real_date_b);

        if (pB_bin) counts.revb.plan[pB_bin]++;
        if (fB_bin) counts.revb.fcst[fB_bin]++;
        if (rB_bin) counts.revb.real[rB_bin]++;

        const p0_bin = getBinDate(d.plan_date_0);
        const f0_bin = getBinDate(d.fcst_date_0);
        const r0_bin = getBinDate(d.real_date_0);

        if (p0_bin) counts.rev0.plan[p0_bin]++;
        if (f0_bin) counts.rev0.fcst[f0_bin]++;
        if (r0_bin) counts.rev0.real[r0_bin]++;
    });

    const revb = { plan_periodic: [], plan_cum: [], fcst_periodic: [], fcst_cum: [], actual_periodic: [], actual_cum: [] };
    const rev0 = { plan_periodic: [], plan_cum: [], fcst_periodic: [], fcst_cum: [], actual_periodic: [], actual_cum: [] };

    timeline.forEach(t => {
        const tDate = new Date(t + "T00:00:00");

        const planB_cum = deliverables.filter(d => d.plan_date_b && new Date(d.plan_date_b + "T00:00:00") <= tDate).length;
        const fcstB_cum = deliverables.filter(d => d.fcst_date_b && new Date(d.fcst_date_b + "T00:00:00") <= tDate).length;
        const realB_cum = deliverables.filter(d => d.real_date_b && new Date(d.real_date_b + "T00:00:00") <= tDate).length;

        const plan0_cum = deliverables.filter(d => d.plan_date_0 && new Date(d.plan_date_0 + "T00:00:00") <= tDate).length;
        const fcst0_cum = deliverables.filter(d => d.fcst_date_0 && new Date(d.fcst_date_0 + "T00:00:00") <= tDate).length;
        const real0_cum = deliverables.filter(d => d.real_date_0 && new Date(d.real_date_0 + "T00:00:00") <= tDate).length;

        revb.plan_periodic.push(counts.revb.plan[t]);
        revb.fcst_periodic.push(counts.revb.fcst[t]);
        revb.plan_cum.push(planB_cum);
        revb.fcst_cum.push(fcstB_cum);

        if (tDate <= controlDate) {
            revb.actual_periodic.push(counts.revb.real[t]);
            revb.actual_cum.push(realB_cum);
        } else {
            revb.actual_periodic.push(null);
            revb.actual_cum.push(null);
        }

        rev0.plan_periodic.push(counts.rev0.plan[t]);
        rev0.fcst_periodic.push(counts.rev0.fcst[t]);
        rev0.plan_cum.push(plan0_cum);
        rev0.fcst_cum.push(fcst0_cum);

        if (tDate <= controlDate) {
            rev0.actual_periodic.push(counts.rev0.real[t]);
            rev0.actual_cum.push(real0_cum);
        } else {
            rev0.actual_periodic.push(null);
            rev0.actual_cum.push(null);
        }
    });

    return {
        weeks: timeline,
        labels: labels,
        revb: revb,
        rev0: rev0
    };
}

