+        // Dynamic S-Curve Generation Engine
+        function calculateSCurveTimeline(deliverables, controlDateStr, scaleType, startDateStr, endDateStr) {
+            const controlDate = new Date(controlDateStr + "T00:00:00");
+            const startLimit = new Date(startDateStr + "T00:00:00");
+            const endLimit = new Date(endDateStr + "T00:00:00");
