+                    rev0: { plan_periodic: [], plan_cum: [], fcst_periodic: [], fcst_cum: [], actual_periodic: [], actual_cum: [] }
+                };
+            }
+            
+            function getBinDate(dateStr) {
+                if (!dateStr) return null;
+                const d = new Date(dateStr + "T00:00:00");
+                for (let i = 0; i < timeline.length; i++) {
+                    const tDate = new Date(timeline[i] + "T00:00:00");
+                    if (d <= tDate) return timeline[i];
+                }
+                return timeline[timeline.length - 1];
+            }
+            
+            const counts = {
+                revb: { plan: {}, fcst: {}, real: {} },
+                rev0: { plan: {}, fcst: {}, real: {} }
+            };
+            
+            timeline.forEach(t => {
+                counts.revb.plan[t] = 0; counts.revb.fcst[t] = 0; counts.revb.real[t] = 0;
+                counts.rev0.plan[t] = 0; counts.rev0.fcst[t] = 0; counts.rev0.real[t] = 0;
+            });
+            
+            deliverables.forEach(d => {
+                const pB_bin = getBinDate(d.plan_date_b);
+                const fB_bin = getBinDate(d.fcst_date_b);
+                const rB_bin = getBinDate(d.real_date_b);
+                
+                if (pB_bin) counts.revb.plan[pB_bin]++;
+                if (fB_bin) counts.revb.fcst[fB_bin]++;
+                if (rB_bin) counts.revb.real[rB_bin]++;
+                
+                const p0_bin = getBinDate(d.plan_date_0);
+                const f0_bin = getBinDate(d.fcst_date_0);
+                const r0_bin = getBinDate(d.real_date_0);
+                
+                if (p0_bin) counts.rev0.plan[p0_bin]++;
+                if (f0_bin) counts.rev0.fcst[f0_bin]++;
