+            
+            timeline.forEach(t => {
+                const tDate = new Date(t + "T00:00:00");
+                
+                const planB_cum = deliverables.filter(d => d.plan_date_b && new Date(d.plan_date_b + "T00:00:00") <= tDate).length;
+                const fcstB_cum = deliverables.filter(d => d.fcst_date_b && new Date(d.fcst_date_b + "T00:00:00") <= tDate).length;
