+                const fcst0_cum = deliverables.filter(d => d.fcst_date_0 && new Date(d.fcst_date_0 + "T00:00:00") <= tDate).length;
+                const real0_cum = deliverables.filter(d => d.real_date_0 && new Date(d.real_date_0 + "T00:00:00") <= tDate).length;
+                
+                revb.plan_periodic.push(counts.revb.plan[t]);
+                revb.fcst_periodic.push(counts.revb.fcst[t]);
+                revb.plan_cum.push(planB_cum);
+                revb.fcst_cum.push(fcstB_cum);
+                
+                if (tDate <= controlDate) {
