+                } else {
+                    rev0.actual_periodic.push(null);
+                    rev0.actual_cum.push(null);
+                }
+            });
+            
+            return {
+                weeks: timeline,
+                labels: labels,
+                revb: revb,
+                rev0: rev0
+            };
