import pandas as pd
import openpyxl

file_path = r"c:\Users\Pablo Villegas\OneDrive\Documents\Claude\Docs Control\Planilla Control_150626 rev1 Input.xlsx"
df_raw = pd.read_excel(file_path, sheet_name="Planilla Control", header=None)

# Print row 3 (headers)
headers = df_raw.iloc[2].tolist()
print("Excel headers:")
for idx, h in enumerate(headers):
    if pd.notna(h):
        print(f"Col {idx+1}: {h}")

# Search for "HCH" in any cell
print("\nSearching for 'HCH' in cell values:")
hch_found = []
for r_idx, row in df_raw.iterrows():
    for c_idx, val in enumerate(row):
        if pd.notna(val) and "hch" in str(val).lower():
            hch_found.append((r_idx+1, c_idx+1, val))
            if len(hch_found) <= 10:
                print(f"Row {r_idx+1}, Col {c_idx+1}: {val}")

print(f"Total cells containing 'HCH': {len(hch_found)}")

