// State variables
let currentWeek = "";
let compareWeek = "";
let currentTab = "scurve-tab";
let chartInstances = {};

// Time resolution and slicer window state
let timeScale = "weekly"; // "weekly" or "monthly"
let slicerStart = "";
let slicerEnd = "";
let projectMinDate = "";
let projectMaxDate = "";

// Global filter states
let globalContractor = "";
let globalHchFilter = "";

function changeGlobalContractor(val) {
    globalContractor = val;
    updateDashboard();
}

function changeGlobalHchFilter(val) {
    globalHchFilter = val;
    updateDashboard();
}

function getFilteredDeliverables(deliverablesList) {
    return deliverablesList.filter(d => {
        const matchesContractor = !globalContractor || d.consultor === globalContractor;

        let matchesHch = true;
        if (globalHchFilter === "hch") {
            matchesHch = d.revisa_hch === true;
        } else if (globalHchFilter === "non-hch") {
            matchesHch = d.revisa_hch === false;
        }

        return matchesContractor && matchesHch;
    });
}

