function updateContractorCards(dataObj) {
    const container = document.getElementById("contractor-cards-container");
    container.innerHTML = "";

    const filtered = getFilteredDeliverables(dataObj.deliverables);

    // Group filtered deliverables by contractor
    const contractors = {};
    filtered.forEach(d => {
        if (!contractors[d.consultor]) {
            contractors[d.consultor] = { total: 0, emitted_b: 0, emitted_0: 0, delayed_b: 0, delayed_0: 0 };
        }
        const c = contractors[d.consultor];
        c.total++;
        if (d.real_date_b) c.emitted_b++;
        if (d.real_date_0) c.emitted_0++;
        if (d.estado_b === "Atrasado") c.delayed_b++;
        if (d.estado_0 === "Atrasado") c.delayed_0++;
    });

    Object.keys(contractors).sort().forEach(cName => {
        const c = contractors[cName];
        const card = document.createElement("div");
        card.className = "glass-panel rounded-2xl p-5 space-y-4 hover:scale-[1.01] transition-all";

        const pctB = Math.round((c.emitted_b / c.total) * 100) || 0;
        const pct0 = Math.round((c.emitted_0 / c.total) * 100) || 0;

        card.innerHTML = `
            <div class="flex items-center justify-between border-b border-white/5 pb-3">
                <h4 class="font-outfit font-bold text-lg text-white">${cName}</h4>
                <span class="text-xs px-2.5 py-0.5 rounded-full bg-slate-900 border border-white/15 text-slate-300 font-semibold">
                    ${c.total} Docs
                </span>
            </div>

            <div class="space-y-3">
                <div>
                    <div class="flex justify-between text-xs mb-1">
                        <span class="text-slate-400">Revision B Emitted</span>
                        <span class="text-emerald-400 font-semibold">${c.emitted_b} (${pctB}%)</span>
                    </div>
                    <div class="w-full bg-slate-900 rounded-full h-1.5 border border-white/5">
                        <div class="bg-emerald-500 h-1.5 rounded-full" style="width: ${pctB}%"></div>
                    </div>
                </div>

                <div>
                    <div class="flex justify-between text-xs mb-1">
                        <span class="text-slate-400">Revision 0 Emitted</span>
                        <span class="text-brand-400 font-semibold">${c.emitted_0} (${pct0}%)</span>
                    </div>
                    <div class="w-full bg-slate-900 rounded-full h-1.5 border border-white/5">
                        <div class="bg-brand-500 h-1.5 rounded-full" style="width: ${pct0}%"></div>
                    </div>
                </div>
            </div>

            <div class="grid grid-cols-2 gap-2 text-center text-[10px] uppercase font-bold pt-2">
                <div class="bg-amber-500/10 text-amber-500 border border-amber-500/20 rounded-lg p-2">
                    Delayed B: ${c.delayed_b}
                </div>
                <div class="bg-rose-500/10 text-rose-500 border border-rose-500/20 rounded-lg p-2">
                    Delayed 0: ${c.delayed_0}
                </div>
            </div>
        `;
        container.appendChild(card);
    });
}

