    const filteredCurrent = getFilteredDeliverables(currentWeekData.deliverables);
    const sCurveData = calculateSCurveTimeline(filteredCurrent, currentWeekData.control_date, timeScale, slicerStart, slicerEnd);
    const labels = sCurveData.labels;

    // B-Curve rendering
    const ctxB = document.getElementById('scurveChartB').getContext('2d');
