function applyFilters() {
    const dataObj = PROJECT_DATA.weekly_data[currentWeek];
    if (!dataObj) return;

    const searchQuery = document.getElementById("search-input").value.toLowerCase();
    const filterStatusB = document.getElementById("filter-status-b").value;
    const filterStatus0 = document.getElementById("filter-status-0").value;

    // Apply global filters (Contractor & HCH Review)
    const globalFiltered = getFilteredDeliverables(dataObj.deliverables);

    filteredDeliverables = globalFiltered.filter(d => {
        const matchesSearch = (d.codigo && d.codigo.toLowerCase().includes(searchQuery)) || 
                             (d.title && d.title.toLowerCase().includes(searchQuery));

        const matchesStatusB = !filterStatusB || 
                              (filterStatusB === "Emititido" && d.estado_b === "Emititido") ||
                              (d.estado_b === filterStatusB);
        const matchesStatus0 = !filterStatus0 || 
                              (filterStatus0 === "Emititido" && d.estado_0 === "Emititido") ||
                              (d.estado_0 === filterStatus0);

        return matchesSearch && matchesStatusB && matchesStatus0;
    });

    currentPage = 1;
    renderListTable();
}

function renderListTable() {
    const dataObj = PROJECT_DATA.weekly_data[currentWeek];
    if (!dataObj) return;

    const tbody = document.getElementById("deliverables-tbody");
    tbody.innerHTML = "";

    const totalFiltered = filteredDeliverables.length;
    const totalPages = Math.ceil(totalFiltered / itemsPerPage) || 1;

    if (currentPage > totalPages) currentPage = totalPages;

    document.getElementById("table-stats").textContent = `Showing ${Math.min(totalFiltered, (currentPage-1)*itemsPerPage + 1)}-${Math.min(totalFiltered, currentPage*itemsPerPage)} of ${totalFiltered} deliverables`;
    document.getElementById("page-indicator").textContent = `Page ${currentPage} of ${totalPages}`;

    document.getElementById("prev-page-btn").disabled = currentPage === 1;
    document.getElementById("next-page-btn").disabled = currentPage === totalPages;

    const weeks = dataObj.s_curves.weeks;

    // Rebuild header row to dynamically support week columns
    const headerRow = document.getElementById("table-header-row");
    headerRow.innerHTML = `
        <th class="p-4 sticky left-0 bg-slate-950 z-10 border-r border-white/5 shadow-[2px_0_5px_rgba(0,0,0,0.2)]">Code</th>
        <th class="p-4">Consultor</th>
        <th class="p-4">Deliverable Title</th>
        <th class="p-4">Rev B (Plan / Fcst / Actual)</th>
        <th class="p-4">Status B</th>
        <th class="p-4">Rev 0 (Plan / Fcst / Actual)</th>
        <th class="p-4">Status 0</th>
    `;

    weeks.forEach(w => {
        const th = document.createElement("th");
        th.className = "p-2 text-center font-mono font-medium text-[10px] min-w-[55px] border-l border-white/5";

        // Format date as DD-MMM
        const date = new Date(w + "T00:00:00");
        const months = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
        th.textContent = `${date.getDate()}-${months[date.getMonth()]}`;
        headerRow.appendChild(th);
    });

    const startIndex = (currentPage - 1) * itemsPerPage;
    const pageItems = filteredDeliverables.slice(startIndex, startIndex + itemsPerPage);

    if (pageItems.length === 0) {
        tbody.innerHTML = `
            <tr>
                <td colspan="${7 + weeks.length}" class="p-8 text-center text-slate-500 font-medium">
                    No deliverables found matching the active filters.
                </td>
            </tr>
        `;
        return;
    }

    pageItems.forEach(d => {
        const tr = document.createElement("tr");
        tr.className = "hover:bg-white/2 border-b border-white/5 transition-all duration-150";

        const badgeB = getStatusBadge(d.estado_b);
        const badge0 = getStatusBadge(d.estado_0);

        let titleHtml = d.title || '-';
        if (d.revisa_hch) {
            titleHtml = `
                <div class="flex items-center space-x-2">
                    <span class="truncate text-slate-200" title="${d.title || ''}">${d.title || '-'}</span>
                    <span class="flex-shrink-0 px-1.5 py-0.5 rounded text-[8px] font-bold bg-amber-500/10 text-amber-500 border border-amber-500/20 uppercase tracking-wider" title="Revisión de HCH">HCH</span>
                </div>
            `;
        } else {
            titleHtml = `<span class="truncate text-slate-200" title="${d.title || ''}">${d.title || '-'}</span>`;
        }

        let rowHtml = `
            <td class="p-4 font-mono font-medium text-[11px] text-white break-all max-w-[180px] sticky left-0 bg-[#111827] z-10 border-r border-white/5 shadow-[2px_0_5px_rgba(0,0,0,0.2)]">${d.codigo || '-'}</td>
            <td class="p-4"><span class="font-semibold text-slate-300">${d.consultor || '-'}</span></td>
            <td class="p-4 max-w-[300px]">${titleHtml}</td>
            <td class="p-4">
                <div class="space-y-0.5 text-[11px]">
                    <div class="text-slate-500"><span class="w-8 inline-block font-semibold">PLN:</span> ${formatDate(d.plan_date_b)}</div>
                    <div class="text-amber-500/80"><span class="w-8 inline-block font-semibold">FCS:</span> ${formatDate(d.fcst_date_b)}</div>
                    <div class="text-emerald-500/80"><span class="w-8 inline-block font-semibold">ACT:</span> ${formatDate(d.real_date_b)}</div>
                </div>
            </td>
            <td class="p-4">${badgeB}</td>
            <td class="p-4">
                <div class="space-y-0.5 text-[11px]">
                    <div class="text-slate-500"><span class="w-8 inline-block font-semibold">PLN:</span> ${formatDate(d.plan_date_0)}</div>
                    <div class="text-amber-500/80"><span class="w-8 inline-block font-semibold">FCS:</span> ${formatDate(d.fcst_date_0)}</div>
                    <div class="text-emerald-500/80"><span class="w-8 inline-block font-semibold">ACT:</span> ${formatDate(d.real_date_0)}</div>
                </div>
            </td>
            <td class="p-4">${badge0}</td>
        `;

        weeks.forEach(w => {
            const val = d.weekly_progress ? d.weekly_progress[w] : null;
            let cellContent = "-";
            if (val) {
                const valUpper = val.toUpperCase().trim();
                if (valUpper === "VERDE") {
                    cellContent = `<span class="w-2 h-2 rounded-full bg-emerald-500 inline-block" title="VERDE"></span>`;
                } else if (valUpper === ".") {
                    cellContent = `<span class="w-1 h-1 rounded-full bg-slate-600 inline-block" title="Active"></span>`;
                } else {
                    cellContent = `<span class="font-semibold text-slate-300 font-mono text-[9px]">${val}</span>`;
                }
            } else {
                cellContent = `<span class="text-slate-800 text-[9px]">-</span>`;
            }
            rowHtml += `<td class="p-1 text-center border-l border-white/5 min-w-[55px]">${cellContent}</td>`;
        });

        tr.innerHTML = rowHtml;
        tbody.appendChild(tr);
    });
}

